import React from 'react';

export default function Games() {
  const games = [
    { id: 1, title: 'Mystic Quest', genre: 'Adventure', color: 'yellow' },
    { id: 2, title: 'Space Racer', genre: 'Racing', color: 'green' },
  ];

  return (
    <main>
      <h1>Browse Our Selection</h1>
      <section>
        {games.map(g => (
          <GameCard key={g.id} title={g.title} genre={g.genre} color={g.color} />
        ))}
      </section>
    </main>
  );
}

function GameCard({ title, genre, color }) {
  return (
    <article className="game-card">
      <h2>{title}</h2>
      <p>{genre}</p>
      <p>{color}</p>
    </article>
  );
}
